with:
  for subj, group in subject_groups.items():
          parts = []
          for i, t in enumerate(group):
              verb = verb_map.get(t.predicate, t.predicate)
              obj = format_object(t.object)
              if i == 0:
                  # First predicate includes the subject
                  parts.append(f"{subj} {verb} {obj}")
              else:
                  # Use a relative clause for predicates that start with “is”, “has” or “lies”
                  if verb.startswith("is ") or verb.startswith("has ") or verb.startswith("lies"):
                      parts.append(f"which {verb} {obj}")
                  else:
                      parts.append(f"and {verb} {obj}")
          # Join predicates for this subject into a single clause
          clause = ", ".join(parts)
          subject_clauses.append(clause)
